"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[85817],{76888:e=>{e.exports=JSON.parse('{"functions":[{"name":"SetQueryOwnershipCallback","desc":"Sets the callback which will query ownership","params":[{"name":"promiseOwnsAsset","desc":"","lua_type":"function"}],"returns":[],"function_type":"method","source":{"line":102,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}},{"name":"SetOwnership","desc":"Sets the players ownership of a the asset","params":[{"name":"idOrKey","desc":"","lua_type":"number"},{"name":"ownsAsset","desc":"","lua_type":"boolean"}],"returns":[],"function_type":"method","source":{"line":159,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}},{"name":"SetOwnershipOverride","desc":"Sets a server-authoritative override for the player\'s ownership of the asset. When set, the\\noverride wins over the cloud query and any session purchase, forcing ownership on (`true`) or off\\n(`false`). Passing `nil` clears the override so ownership falls back to the cloud query again\\n(equivalent to [PlayerAssetOwnershipTracker.ClearOwnershipOverride]).\\n\\nThe override is published into a replicated attribute and applied on every realm, so it drives\\nclient-side ownership-gated UI. Only the server can assign it: the client-facing service exposes\\nno setter and [GameProductService.SetPlayerOwnershipOverride] guards the server realm, so a player\\ncan never grant themselves ownership. Callers should go through that service, never here directly.","params":[{"name":"self","desc":"","lua_type":"any"},{"name":"idOrKey","desc":"","lua_type":"number | string"},{"name":"ownsAsset","desc":"","lua_type":"boolean?"}],"returns":[],"function_type":"static","source":{"line":190,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}},{"name":"ClearOwnershipOverride","desc":"Clears any local ownership override for the asset, so ownership falls back to the cloud\\nquery. Equivalent to `SetOwnershipOverride(idOrKey, nil)`.","params":[{"name":"self","desc":"","lua_type":"any"},{"name":"idOrKey","desc":"","lua_type":"number | string"}],"returns":[],"function_type":"static","source":{"line":250,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}},{"name":"PromiseOwnsAsset","desc":"Promises true if the user owns the asset and false otherwise","params":[{"name":"idOrKey","desc":"","lua_type":"string | number"}],"returns":[{"desc":"","lua_type":"Promise<boolean>"}],"function_type":"method","source":{"line":262,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}},{"name":"ObserveOwnsAsset","desc":"Observes whether the player owns the asset or not","params":[{"name":"idOrKey","desc":"","lua_type":"number | number"}],"returns":[{"desc":"","lua_type":"Observable<boolean>"}],"function_type":"method","source":{"line":297,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}},{"name":"_observeOwnsAssetId","desc":"Observes ownership of a resolved numeric asset id, layering the local override on top of\\nthe cloud query. When an override is present it wins and short-circuits the query; when it\\nis cleared, ownership falls back to the cloud query and owned-asset set.","params":[{"name":"self","desc":"","lua_type":"any"},{"name":"assetId","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"Observable<boolean>"}],"function_type":"static","source":{"line":334,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}},{"name":"_observeBaseOwnsAssetId","desc":"Observes ownership of a numeric asset id from the cloud query and owned-asset set only,\\nwithout applying any override. Only fires once ownership status has been resolved.","params":[{"name":"self","desc":"","lua_type":"any"},{"name":"assetId","desc":"","lua_type":"number"}],"returns":[{"desc":"","lua_type":"Observable<boolean>"}],"function_type":"static","source":{"line":358,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}}],"properties":[],"types":[],"name":"PlayerAssetOwnershipTracker","desc":"Tracks whether a player owns a given asset. Ownership resolves from an async cloud\\nquery (see [PlayerAssetOwnershipTracker:SetQueryOwnershipCallback]) plus session\\npurchases, with an optional local override layered on top.\\n\\nThe override (see [PlayerAssetOwnershipTracker:SetOwnershipOverride]) is an authoritative layer:\\nwhen set it wins over the cloud query and session purchases, forcing ownership on (`true`) or off\\n(`false`). It is stored in a server-owned [JSONAttributeValue] on the player that Roblox\\nreplicates read-only to clients, so every realm applies the same overrides but only the server\\ncan assign them -- a player can never grant themselves ownership.","source":{"line":15,"path":"src/gameproductservice/src/Shared/Ownership/PlayerAssetOwnershipTracker.lua"}}')}}]);